<template>
  <div class="orderlist" >
    <div class="shopstate" v-show="user.orderStatusNum">
      <div class="order">
        <van-icon name="arrow-left" @click="$router.back()" />
        <p>我的订单</p>
        <van-icon name="service-o" />
      </div>
      <van-tabs :ellipsis="false">
        <van-tab>
          <template #title>
            <div @click="type = 0">
              <p>待付款</p>
              <p>{{ user.orderStatusNum.unpaid_count }}</p>
            </div>
          </template>
        </van-tab>
        <van-tab>
          <template #title>
            <div @click="type = 1">
              <p>待发货</p>
              <p>{{ user.orderStatusNum.unshipped_count }}</p>
            </div>
          </template>
        </van-tab>
        <van-tab>
          <template #title>
            <div @click="type = 2">
              <p>待收货</p>
              <p>{{ user.orderStatusNum.received_count }}</p>
            </div>
          </template>
        </van-tab>
        <van-tab>
          <template #title>
            <div @click="type = 3">
              <p>待评价</p>
              <p>{{ user.orderStatusNum.evaluated_count }}</p>
            </div>
          </template>
        </van-tab>
        <van-tab>
          <template #title>
            <div @click="type = 4">
              <p>已完成</p>
              <p>{{ user.orderStatusNum.complete_count }}</p>
            </div>
          </template>
        </van-tab>
      </van-tabs>
    </div>

    <div v-show="shopList">
    <!-- 订单列表 -->
<div class="orderDetail" v-for="item in shopList" :key="item.id">
        <div class="top">
          <p>{{ item._pay_time }}</p>
          <span>{{ item._status._title }}</span>
        </div>
        <div class="content">
          <div class="detail">
            <img :src="item.cartInfo[0].productInfo.image" alt="" />
            <p>{{ item.cartInfo[0].productInfo.store_name }}</p>
            <div class="num">
            <p>￥{{ item.cartInfo[0].productInfo.price }}</p>
            <p>x {{ item.total_num }}</p>
            </div>
          </div>
          <p class="totalPrice"> 总额为 <label>￥{{ item.total_price }} </label></p>

    <div class="button" v-if="item._status._title=='未支付'">
        <!-- <div class="goDetail">取消订单</div> -->
        <router-link tag="div" :to="`/transition/${num}`" class="goDetail">查看详情</router-link>
    </div>
    <div class="button" v-if="item._status._title=='未发货'">
        <!-- <div class="goDetail">申请退款</div> -->
        <router-link tag="div" :to="`/transition/${item.order_id}`" class="goDetail">查看详情</router-link>
  
          </div>
        </div>
    </div>
    </div>

    <div class="none" v-show="shopList.length<=0">
        <img src="../assets/noCart.png" alt="">
    </div>
    </div>
</template>
<script>
export default {
  data(){
    return {
      type: 0,
      user: "",
      shopList: [],

    };
  },
  created() {
        this.num  = this.$route.query.num
    this.axios.get("/api/user").then((d) => {
      this.user = d.data.data;
    //   console.log(this.user);
    }),
      this.axios
        .get("/api/order/list?page=1&limit=20&type=" + this.type)
        .then((da) => {
          this.shopList = da.data.data;
        //  console.log(this.shopList);
        });
  },
  watch: {
    type(newval) {
      this.axios
        .get("/api/order/list?page=1&limit=20&type=" + newval)
        .then((da) => {
          this.shopList = da.data.data;
        });
    },
  },
};
</script>
<style lang="less">
.orderlist {
  z-index: 9;
  position: fixed;
  top: 0;
  left: 0;
  width: 375px;
  height: 100vh;
  background-color: rgb(248, 248, 248);
  overflow-y: auto;
  font-size: 14px;
  p {
    margin: 0;
  }
  .shopstate {
    background-color: #fff;
    margin-bottom: 10px;
    .order {
      display: flex;
      justify-content: space-between;
      align-items: center;
      padding: 0 10px;
      height: 50px;
      border-bottom: 0.5px solid whitesmoke;
      font-size: 16px;
    }
    .van-tabs--line .van-tabs__wrap {
      height: 60px;
      text-align: center;
    }
  }
  .orderDetail{
      padding:0 10px;
      padding-bottom: 10px;
      background-color: #fff;
      margin: 10px 0;
      .top{
          display: flex;
          justify-content: space-between;
             height: 50px;
             align-items: center;
             border-bottom: .5px solid whitesmoke;
             span{
                 color: tomato;
             }
      }
      .content{
  .detail{
      display: flex;
      justify-content: space-between;
      align-items: center;
      img{
          width: 100px;
          height: 100px;
      }
      &>p{
        width: 45%;
        overflow: hidden;
        text-overflow: ellipsis;
        display: -webkit-box;
        -webkit-line-clamp: 2;
        -webkit-box-orient: vertical;
      }
      .num{
          text-align: right;
          color: #666;
      }
  }
  .totalPrice{
      text-align: right;
   label{
       color: tomato;
   }
  }
  .button{
      display: flex;
  .goDetail{
      color: white;
      text-align: center;
      line-height: 30px;
      border-radius: 20px;
      width: 80px;
      height: 30px;
      padding: 1px;
      margin: 5px 20px;      
      background-color: tomato;
  }
  
  }
      }
  }
 .none{
     img{
         width: 100%;
        height: auto;
     }
 }
}
</style>